package com.example.demo.category.presentation.request;

import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.Size;
import org.jspecify.annotations.Nullable;

/** Category 作成リクエスト。 */
public record CreateCategoryRequest(
    @NotBlank(message = "カテゴリ名は必須です") @Size(max = 50, message = "カテゴリ名は50文字以内です") String name,
    int sortOrder,
    @Nullable String parentCategoryId) {}

package com.example.demo.category.presentation.request;

import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.Size;

/** Category 更新リクエスト。 */
public record UpdateCategoryRequest(
    @NotBlank(message = "カテゴリ名は必須です") @Size(max = 50, message = "カテゴリ名は50文字以内です") String name,
    int sortOrder,
    int version) {}

package com.example.demo.category.presentation.request;

import org.jspecify.annotations.Nullable;

/** Category 移動リクエスト。 */
public record MoveCategoryRequest(@Nullable String newParentCategoryId, int version) {}

package com.example.demo.category.presentation.response;

import com.example.demo.category.application.query.dto.CategoryDetailDto;
import java.util.List;
import org.jspecify.annotations.Nullable;

/** Category 詳細レスポンス。 */
public record CategoryDetailResponse(
    String id,
    String name,
    int sortOrder,
    @Nullable String parentCategoryId,
    int version,
    List<AncestorResponse> ancestors) {

  /** 祖先カテゴリレスポンス。 */
  public record AncestorResponse(String id, String name) {}

  /** DTO から変換する。 */
  public static CategoryDetailResponse from(final CategoryDetailDto dto) {
    final List<AncestorResponse> ancestors =
        dto.ancestors().stream().map(a -> new AncestorResponse(a.id(), a.name())).toList();
    return new CategoryDetailResponse(
        dto.id(), dto.name(), dto.sortOrder(), dto.parentCategoryId(), dto.version(), ancestors);
  }
}

package com.example.demo.category.presentation.response;

import com.example.demo.category.application.query.dto.CategorySummaryDto;

/** Category 一覧レスポンス。 */
public record CategorySummaryResponse(String id, String name, int sortOrder) {

  /** DTO から変換する。 */
  public static CategorySummaryResponse from(final CategorySummaryDto dto) {
    return new CategorySummaryResponse(dto.id(), dto.name(), dto.sortOrder());
  }
}

