import { apiClient } from "@/lib/api-client";
import type {
  CategoryDetail,
  CategorySummary,
  CreateCategoryInput,
  Page,
  UpdateCategoryInput,
} from "@/features/category/types/category";

export function getCategories(page: number, size: number): Promise<Page<CategorySummary>> {
  return apiClient<Page<CategorySummary>>({
    url: "/categories",
    method: "GET",
    params: { page: String(page), size: String(size) },
  });
}

export function getCategory(id: string): Promise<CategoryDetail> {
  return apiClient<CategoryDetail>({
    url: `/categories/${id}`,
    method: "GET",
  });
}

export function createCategory(input: CreateCategoryInput): Promise<undefined> {
  return apiClient<undefined>({
    url: "/categories",
    method: "POST",
    data: input,
  });
}

export function updateCategory(id: string, input: UpdateCategoryInput): Promise<undefined> {
  return apiClient<undefined>({
    url: `/categories/${id}`,
    method: "PUT",
    data: input,
  });
}

export function deleteCategory(id: string, version: number): Promise<undefined> {
  return apiClient<undefined>({
    url: `/categories/${id}`,
    method: "DELETE",
    data: { version },
  });
}

