import { useState } from "react";
import { Button } from "@/components/ui/button";

interface CategoryFormProps {
  readonly initialValues?: {
    readonly name: string;
    readonly sortOrder: number;
    readonly parentCategoryId: string | null;
  };
  readonly onSubmit: (data: {
    name: string;
    sortOrder: number;
    parentCategoryId: string | null;
  }) => void;
  readonly isSubmitting: boolean;
  readonly submitLabel: string;
}

export function CategoryForm({
  initialValues,
  onSubmit,
  isSubmitting,
  submitLabel,
}: CategoryFormProps) {
  const [name, setName] = useState(initialValues?.name ?? "");
  const [sortOrder, setSortOrder] = useState(String(initialValues?.sortOrder ?? 0));
  const [parentCategoryId, setParentCategoryId] = useState(
    initialValues?.parentCategoryId ?? "",
  );

  function handleSubmit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    onSubmit({
      name,
      sortOrder: Number(sortOrder),
      parentCategoryId: parentCategoryId.length > 0 ? parentCategoryId : null,
    });
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-4 max-w-md">
      <div>
        <label htmlFor="name" className="text-sm font-medium">
          カテゴリ名
        </label>
        <input
          id="name"
          type="text"
          value={name}
          onChange={(e) => { setName(e.target.value); }}
          required
          maxLength={50}
          className="mt-1 w-full rounded-md border px-3 py-2"
        />
      </div>

      <div>
        <label htmlFor="sortOrder" className="text-sm font-medium">
          表示順
        </label>
        <input
          id="sortOrder"
          type="number"
          value={sortOrder}
          onChange={(e) => { setSortOrder(e.target.value); }}
          required
          className="mt-1 w-full rounded-md border px-3 py-2"
        />
      </div>

      <div>
        <label htmlFor="parentCategoryId" className="text-sm font-medium">
          親カテゴリID（任意）
        </label>
        <input
          id="parentCategoryId"
          type="text"
          value={parentCategoryId}
          onChange={(e) => { setParentCategoryId(e.target.value); }}
          className="mt-1 w-full rounded-md border px-3 py-2"
          placeholder="ルートカテゴリの場合は空"
        />
      </div>

      <Button type="submit" disabled={isSubmitting}>
        {isSubmitting ? "送信中..." : submitLabel}
      </Button>
    </form>
  );
}

