import { useMutation, useQueryClient } from "@tanstack/react-query";
import { apiClient } from "@/lib/api-client";

interface ChangeStatusParams {
  readonly id: string;
  readonly version: number;
}

export function useChangeProductStatus() {
  const queryClient = useQueryClient();

  function createMutation(action: string) {
    return useMutation({
      mutationFn: ({ id, version }: ChangeStatusParams) =>
        apiClient<undefined>({
          url: `/products/${id}/${action}`,
          method: "PATCH",
          data: { version },
        }),
      onSuccess: (_, variables) => {
        void queryClient.invalidateQueries({ queryKey: ["products", variables.id] });
        void queryClient.invalidateQueries({ queryKey: ["products"] });
      },
    });
  }

  const publishMutation = createMutation("publish");
  const unpublishMutation = createMutation("unpublish");
  const archiveMutation = createMutation("archive");

  return {
    publish: publishMutation.mutate,
    unpublish: unpublishMutation.mutate,
    archive: archiveMutation.mutate,
    isPending:
      publishMutation.isPending || unpublishMutation.isPending || archiveMutation.isPending,
  };
}

